import sqlite3

class StudentORM:
    conn = sqlite3.connect(':memory:')

    def __init__(self, name, score, id=None):
        self.id = id
        self.name = name
        self.score = score

    @classmethod
    def create_table(cls):
        cls.conn.execute('CREATE TABLE IF NOT EXISTS students (id INTEGER PRIMARY KEY AUTOINCREMENT, name TEXT, score INTEGER)')
        cls.conn.commit()
        print('Table created')

    def save(self):
        if self.id is None:
            cursor = self.conn.execute('INSERT INTO students (name, score) VALUES (?, ?)', (self.name, self.score))
            self.id = cursor.lastrowid
            self.conn.commit()
            print(f'Saved: {self.name} (id={self.id})')

    @classmethod
    def find_all(cls):
        rows = cls.conn.execute('SELECT * FROM students').fetchall()
        return [cls(row[1], row[2], row[0]) for row in rows]

    def __repr__(self):
        return f'Student({self.id}, {self.name}, {self.score})'

StudentORM.create_table()
