import secrets
import hashlib
import hmac

class CSRFProtection:
    def __init__(self, secret):
        self.secret = secret
    def generate(self, session_id):
        random_part = secrets.token_hex(16)
        signature = hmac.new(self.secret.encode(), f'{session_id}{random_part}'.encode(), hashlib.sha256).hexdigest()
        return f'{random_part}:{signature}'
    def validate(self, token, session_id):
        try:
            random_part, signature = token.split(':')
            expected = hmac.new(self.secret.encode(), f'{session_id}{random_part}'.encode(), hashlib.sha256).hexdigest()
            return hmac.compare_digest(signature, expected)
        except (ValueError, AttributeError):
            return False

