def dfs(graph, start):
    visited = []
    stack = [start]
    seen = set()
    while stack:
        node = stack.pop()
        if node not in seen:
            seen.add(node)
            visited.append(node)
            for neighbour in reversed(graph[node]):
                if neighbour not in seen:
                    stack.append(neighbour)
    return visited

