def handle_response(status_code, body=''):
    status_map = {
        200: 'OK - Success',
        201: 'Created - Resource created',
        301: 'Redirect - Resource moved',
        400: 'Bad Request - Client error',
        404: 'Not Found - Resource not found',
        500: 'Internal Server Error - Server error'
    }
    return status_map.get(status_code, f'Unknown status {status_code}')

for code in [200, 201, 301, 400, 404, 500]:
    print(f'{code}: {handle_response(code)}')

def add(a, b): return a + b
def divide(a, b):
    if b == 0: raise ValueError
    return a / b

def test_add_positive():
    assert add(2, 3) == 5

def test_add_negative():
    assert add(-1, -1) == -2

def test_divide_by_zero():
    try:
        divide(1, 0)
        assert False, 'Should have raised'
    except ValueError:
        pass

for test in [test_add_positive, test_add_negative, test_divide_by_zero]:
    try:
        test()
        print(f'{test.__name__}: PASSED')
    except AssertionError as e:
        print(f'{test.__name__}: FAILED - {e}')

import time
from collections import deque

class RateLimiter:
    def __init__(self, max_requests, window_seconds):
        self.max_requests = max_requests
        self.window = window_seconds
        self.requests = deque()
    def allow(self):
        now = time.time()
        while self.requests and self.requests[0] < now - self.window:
            self.requests.popleft()
        if len(self.requests) < self.max_requests:
            self.requests.append(now)
            return True
        return False

limiter = RateLimiter(max_requests=3, window_seconds=1)
for i in range(5):
    result = limiter.allow()
    print(f'Request {i+1}: {"Allowed" if result else "Denied"}')

from datetime import datetime

class AuditLogger:
    def __init__(self):
        self.logs = []
    def log(self, user, action, result):
        self.logs.append({
            'timestamp': datetime.now().strftime('%Y-%m-%d %H:%M:%S'),
            'user': user,
            'action': action,
            'result': result
        })
    def show_logs(self):
        for entry in self.logs:
            print(f'[{entry["timestamp"]}] {entry["user"]} | {entry["action"]} | {entry["result"]}')

audit = AuditLogger()
audit.log('alice', 'login', 'success')
audit.log('bob', 'login', 'failed')
audit.log('alice', 'delete_file', 'success')
audit.show_logs()

class RBAC:
    def __init__(self):
        self.roles = {}
        self.user_roles = {}
    def add_role(self, role, permissions):
        self.roles[role] = set(permissions)
    def assign_role(self, user, role):
        self.user_roles[user] = role
    def can(self, user, permission):
        role = self.user_roles.get(user)
        if not role:
            return False
        return permission in self.roles.get(role, set())

rbac = RBAC()
rbac.add_role('admin', ['read', 'write', 'delete'])
rbac.add_role('editor', ['read', 'write'])
rbac.add_role('viewer', ['read'])
rbac.assign_role('alice', 'admin')
rbac.assign_role('bob', 'editor')

print(rbac.can('alice', 'delete'))
print(rbac.can('bob', 'delete'))
print(rbac.can('bob', 'write'))
